public int rangeSum(int[] nums, int n, int left, int right) {
    int MOD = (int)1e9 + 7;
    int[] sums = new int[n * (n + 1) / 2];
    int index = 0;
    for (int i = 0; i < n; ++i) {
        int sum = 0;
        for (int j = i; j < n; ++j) {
            sum += nums[j];
            sums[index++] = sum;
        }
